{
  "mode": "io",
  "tests": [
    {
      "name": "basic_case",
      "input": "1\n2\n",
      "output": "3\n",
      "notes": "Basic addition of two numbers."
    },
    {
      "name": "negative_numbers",
      "input": "-1\n-2\n",
      "output": "-3\n",
      "notes": "Testing addition with negative numbers."
    },
    {
      "name": "zero_case",
      "input": "0\n0\n",
      "output": "0\n",
      "notes": "Adding two zeros should return zero."
    },
    {
      "name": "large_numbers",
      "input": "1000000\n2000000\n",
      "output": "3000000\n",
      "notes": "Testing addition with large integers."
    },
    {
      "name": "edge_case_one",
      "input": "1\n-1\n",
      "output": "0\n",
      "notes": "Adding one and negative one should return zero."
    },
    {
      "name": "edge_case_two",
      "input": "2147483647\n1\n",
      "output": "2147483648\n",
      "notes": "Testing addition that exceeds 32-bit integer limit."
    },
    {
      "name": "decimal_case",
      "input": "1.5\n2.5\n",
      "output": "4.0\n",
      "notes": "Testing addition with decimal numbers."
    },
    {
      "name": "string_input_case",
      "input": "1\n'2'\n",
      "output": "Error: Invalid input\n",
      "notes": "Testing input validation with string type."
    }
  ],
  "assumptions": "Input will always be two numbers, either integers or floats.",
  "notes": "Ensure to handle both valid and invalid inputs gracefully."
}
